`mutationWithClientMuationId`'s output type is `${name}Payload`, while ClientIDMutation's is just the class name, which means the code on the client-side is needed to modify when the server-side is switched to `graphene`.

```javascript
var RemoveWidgetMutation = mutationWithClientMutationId({
  name : "RemoveWidget",
  inputFields : {
    id : {type:new GraphQLNonNull(GraphQLString)}
  },
  outputFields : {
    viewer : {
      type : userType,
      resolve : ()=>getViewer()
    },
    deletedWidgetID :  {
      type : GraphQLString,
      resolve : (obj) => {
        console.log(obj);
        return obj.id;
      }
    }
  },
  mutateAndGetPayload : ({id}) => {
    removeWidget(fromGlobalId(id).id)
    return {id};
  }
})

```

output type : `RemoveWidgetPayload`

```python
class RemoveWidget(graphene.relay.ClientIDMutation):

    class Input:
        id = graphene.String(required=True)
    
    deletedWidgetID = graphene.String()
    viewer = graphene.Field(User)
    
    @classmethod
    def mutate_and_get_payload(cls, input, info):
        id = input.get("id")
        widgetId = graphene.relay.from_global_id(id)
        widgetToRemove = WidgetModel.objects.get(widgetId)
        user = widgetToRemove.user
        widgetToRemove.remove()
        return RemoveWidget(deletedWidgetID=id, viewer=user)
```

output type : `RemoveWidget`

client-side code:
```javascript
class RemoveWidgetMutation extends Relay.Mutation {
  static fragments = {
    viewer : () => Relay.QL`
      fragment on User {
        id
      }
    `,
    widget : () => Relay.QL`
      fragment on Widget {
        id
      }
    `,
  };

  getMutation() {
    return Relay.QL`mutation{removeWidget}`;
  }

  getFatQuery() {
    return Relay.QL`
      fragment on RemoveWidgetPayload {
        viewer
      }
    `;
  }

  getConfigs() {
    return [{
      type : "NODE_DELETE",
      parentName : "viewer",
      parentID : this.props.viewer.id,
      connectionName : "widgets",
      deletedIDFieldName : "deletedWidgetID"
    }]
  }

  getVariables() {
    return {
      id : this.props.widget.id
    }
  }
}
```

